<!-- CommentModal.vue -->
<template>
  <div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal-backdrop fade show" @click="Close"></div>
    
    <div class="modal d-block">
      <div class="modal-dialog modal-dialog-centered modal-lg">
        <div class="modal-content">

          <div class="modal-header theme-primary partition-full d-flex">
            <h4 class="modal-title">{{ $t('Comment') }}</h4>
            <button type="button" class="close" @click="Close">
              <em class="fa fa-times"></em>
            </button>
          </div>

          <div class="modal-body">
            <dynamic-form
              lang="en"
              ref="commentForm"
              :buttons="buttons"
              :schema="FormSchema"
              :mandatorytext="MandatoryString"
              @OnSubmit="onSubmit">
            </dynamic-form>
          </div>

        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
    name: 'CommentModal',
    props: {
        EditData: {
            type: Object,
            required: false,
            default: () => ({})
        }
    },
    data() {
        return {
            isLoading: false,
            MandatoryString: '',
            
            FormSchema: [
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",
                            label: this.$t('Comment'),
                            name: "COMMENT",
                            value: "",
                            placeholder: this.$t('Enter Comment'),
                            config: {
                                rows: 6,
                                maxlength: 500
                            },
                             validationRules: {
                        "required": true,
                    },
                        }
                    ]
                }
            ],

            buttons: [
                {
                    type: "submit",
                    class: "btn btn-primary",
                    text: `<i class='fa fa-save pr-2'></i>${this.$t('Save')}`,
                    isVisible: true
                },
            ]
        };
    },
    
    watch: {
        EditData: {
            immediate: true,
            deep: true,
            handler: function(newVal) {
                debugger
                if (newVal && this.FormSchema[0].Data[0]) {
                    this.FormSchema[0].Data[0].value = newVal.COMMENT || "";
                    
                    if (this.$refs.commentForm) {
                        this.$refs.commentForm.UpdateKeyValue();
                    }
                }
            }
        }
    },
    
    mounted() {
        document.body.style.overflow = 'hidden';
        
        if (this.EditData && this.EditData.COMMENT) {
            this.FormSchema[0].Data[0].value = this.EditData.COMMENT;
        }
                this.$nextTick(() => {
            const textarea = document.querySelector('textarea');
            if (textarea) {
                textarea.focus();
            }
        });
    },
    
    beforeDestroy() {
        // Restore body scroll
        document.body.style.overflow = '';
    },
    
    methods: {
        onSubmit(formfields) {
            debugger;
            
            // Prepare updated data
            const updatedData = {
                ...this.EditData,
                COMMENT: formfields.COMMENT ? formfields.COMMENT.trim() : ""
            };
            
            // Emit event to parent with updated data
            this.$emit('save-comment', updatedData);
            
            // Close modal
            this.Close();
        },
        
        Close() {
            // Emit close event
            this.$emit('Close');
        }
    }
}
</script>